import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_travel_time(pos1, pos2, speed):
        return calculate_distance(pos1, pos2) / speed

    # Initialize best choice metrics
    min_penalty = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        # Calculate time window penalty
        if arrival_time > end_window:
            penalty = (arrival_time - end_window)**2  # penalty increasing quadratically with lateness
        elif arrival_time < start_window:
            penalty = (start_window - arrival_time)  # penalty for being early; waiting time
        else:
            penalty = 0  # No penalty within the time window

        # If the truck arrives earlier, it can wait
        wait_time = 0 if arrival_time >= start_window else (start_window - arrival_time)

        # Consider total delays and waiting as the cost
        total_cost = penalty + wait_time

        # Prefer minimum penalty followed by earliest finishing times
        if total_cost < min_penalty:
            min_penalty = total_cost
            best_node = i

    # If no suitable node is found, best choice is to stay (return None to indicate waiting)
    return best_node
